const config   = $('Dynasty Config').item.json;
const health   = $('Daily Brief: Health Check').item.json;
const stats    = $('Daily Brief: Lead Stats').item.json;
const capital  = $('Daily Brief: Capital Available').item.json;
const deployed = $('Daily Brief: Capital Deployed').item.json;
const date = new Date().toLocaleDateString('en-US',{ weekday:'long', year:'numeric', month:'long', day:'numeric', timeZone:'America/New_York' });
return [{ json: {
  date,
  apiStatus:        health?.ok ? 'ONLINE âœ…' : 'OFFLINE âš ï¸',
  totalLeads:       stats?.total ?? 'N/A',
  hotLeads:         stats?.by_status?.Hot ?? 0,
  qualifiedLeads:   stats?.by_status?.Qualified ?? 0,
  gradeALeads:      stats?.by_grade?.A ?? 0,
  availableCapital: capital?.total_available != null ? `$${Number(capital.total_available).toLocaleString()}` : 'N/A',
  deployedCapital:  deployed?.total_deployed_allocations != null ? `$${Number(deployed.total_deployed_allocations).toLocaleString()}` : 'N/A',
  byStatus:         stats?.by_status ?? {},
}}];

const content = $json?.message?.content;
if (content) return [{ json: { aiText: content, aiError: false } }];
try {
  const c = $('Daily Brief: Compile').item.json;
  return [{ json: {
    aiText: `Dynasty OS Daily Brief â€” ${c.date || new Date().toDateString()}\nâ€¢ API: ${c.apiStatus || 'N/A'}\nâ€¢ Hot Leads: ${c.hotLeads || 0} | Grade A: ${c.gradeALeads || 0}\nâ€¢ Available Capital: ${c.availableCapital || 'N/A'}\nâ€¢ Deployed Capital: ${c.deployedCapital || 'N/A'}\n\nâš ï¸ AI summary unavailable â€” raw data shown.`,
    aiError: true
  }}];
} catch(e) {
  return [{ json: { aiText: 'Dynasty OS Daily Brief: AI summary unavailable. Check PropertyOS dashboard.', aiError: true } }];
}

const source = $json.body || $json;
const message = String(source.chatInput || source.message || source.text || source.prompt || '').trim();
const lower = message.toLowerCase();

let intent = 'STATUS';
let intentReason = 'default_atlas_status';

if (/(deal|analy[sz]e|underwrite|mao|arv)/.test(lower)) {
  intent = 'DEAL_ANALYSIS';
  intentReason = 'deal_or_analysis_keyword';
} else if (/^(talk|chat|explain|why|how|what do you think|recommend|strategy)\b/.test(lower) || lower.includes('talk strategy')) {
  intent = 'OPEN_CONVERSATION';
  intentReason = 'explicit_conversation_request';
} else if (/(score|pipeline|portfolio)/.test(lower)) {
  intent = 'PORTFOLIO_SCORING';
  intentReason = 'portfolio_scoring_keyword';
} else if (/(capital|fund|funding|risk)/.test(lower)) {
  intent = 'CAPITAL_RISK';
  intentReason = 'capital_or_funding_keyword';
} else if (/(campaign|mail|mailer|direct mail)/.test(lower)) {
  intent = 'CAMPAIGN';
  intentReason = 'campaign_or_mail_keyword';
} else if (/(owner|skip trace|skip-trace|skiptrace|ownership)/.test(lower)) {
  intent = 'OWNER_SKIP_TRACE';
  intentReason = 'owner_or_skip_trace_keyword';
} else if (/(chat|talk|explain|why|how|strategy|recommend|what do you think)/.test(lower) || message.length > 80) {
  intent = 'OPEN_CONVERSATION';
  intentReason = 'conversation_keyword_or_long_prompt';
}

const limit = Number(source.limit || source.batchSize || 500);
const requestBody = { ...source, prompt: message, message };

if (intent === 'CAMPAIGN') {
  requestBody.limit = Number.isFinite(limit) ? limit : 500;
  requestBody.campaignType = source.campaignType || 'ALL';
}
if (intent === 'PORTFOLIO_SCORING') {
  requestBody.limit = Number.isFinite(limit) ? limit : 500;
}
if (intent === 'OWNER_SKIP_TRACE') {
  requestBody.limit = Number.isFinite(limit) ? limit : 500;
}

return [{
  json: {
    ...source,
    chatInput: message,
    message,
    sessionId: source.sessionId || null,
    intent,
    intentReason,
    requestBody,
  }
}];

const route = $('Chat: Intent Classifier').item.json || {};
const intent = route.intent || 'STATUS';
const sessionId = route.sessionId || null;
const data = $json || {};

function firstNumber(...values) {
  for (const value of values) {
    const number = Number(value);
    if (Number.isFinite(number)) return number;
  }
  return null;
}

function compact(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value;
  return JSON.stringify(value, null, 2).slice(0, 1200);
}

let output = '';
const statusCode = Number(data.statusCode || data.status || data.response?.status || 0);
const errorMessage = data.error?.message || data.error || data.message || data.detail || '';
if (statusCode >= 400 || data.error) {
  const details = compact(errorMessage);
  if (details.includes('127.0.0.1') || details.includes('localhost') || details.includes('SsrfBlockedIpError')) {
    output = intent.replaceAll('_', ' ') + ' dispatch is live, but n8n Cloud cannot reach the local PropertyOS web URL. Set a public PropertyOS URL or expose this engine on the Railway API.';
  } else if (statusCode === 401 || details.toLowerCase().includes('authentication required') || details.toLowerCase().includes('unauthorized')) {
    output = intent.replaceAll('_', ' ') + ' dispatch reached the public PropertyOS route, but that route requires authenticated access. Add a service auth path or expose a backend automation route for n8n.';
  } else {
    output = intent.replaceAll('_', ' ') + ' dispatch reached the target route but returned ' + (statusCode || 'an error') + (details ? ': ' + details : '.');
  }
  return [{ json: { output, intent, sessionId, raw: data } }];
}

if (intent === 'OPEN_CONVERSATION') {
  output = data.output || data.text || 'Open conversation fallback is online. The dispatcher can route commands now; connect the n8n OpenAI credential to enable full LLM conversation.';
} else if (intent === 'DEAL_ANALYSIS') {
  // Real shape is DynastyAIResponse (backend/app/dynasty_ai/types.py): atlas.action,
  // atlas.confidence, atlas.reason, scorecard.dynasty_fit_score, projected_profit,
  // projected_roi, total_investment - not decision/dealScore/summary, which never existed.
  const atlas = data.atlas || {};
  const totalInvestment = firstNumber(data.total_investment);
  const hasRealDealData = totalInvestment !== null && totalInvestment > 0;

  if (!hasRealDealData) {
    output = 'Deal Engine dispatch complete, but this query had no purchase price or ARV attached, so ATLAS scored a blank property. Open a specific deal from the Deals page for a real analysis, or include the numbers in your message.';
  } else {
    const confidence = firstNumber(atlas.confidence);
    const dynastyFit = firstNumber(data.scorecard?.dynasty_fit_score);
    const projectedProfit = firstNumber(data.projected_profit);
    const projectedRoi = firstNumber(data.projected_roi);
    output = 'Deal Engine dispatch complete.';
    if (atlas.action) output += ' Recommendation: ' + atlas.action + (confidence === null ? '' : ' (confidence ' + confidence + '%)') + '.';
    if (dynastyFit !== null) output += ' Dynasty fit score: ' + dynastyFit + '/100.';
    if (projectedProfit !== null) output += ' Projected profit: $' + projectedProfit.toLocaleString() + '.';
    if (projectedRoi !== null) output += ' Projected ROI: ' + projectedRoi.toFixed(1) + '%.';
    if (Array.isArray(atlas.reason) && atlas.reason.length) output += ' ' + atlas.reason.join(' ');
  }
} else if (intent === 'PORTFOLIO_SCORING') {
  const count = firstNumber(data.scored, data.generated, data.count, data.total, data.scoresCreated);
  output = 'Portfolio Scoring dispatch complete' + (count === null ? '' : ' for ' + count + ' records') + '.';
} else if (intent === 'CAPITAL_RISK') {
  // Real shape is GET /api/capital/available (backend/app/api/capital.py):
  // { total_available, investor_count, investors }. There is no "deployed"
  // figure in this response - that lives behind a separate /deployed route
  // this dispatch never calls, so it's dropped rather than faked.
  const available = firstNumber(data.total_available);
  const investorCount = firstNumber(data.investor_count);
  output = 'Capital Engine dispatch complete.';
  if (available !== null) output += ' Available capital: $' + Math.round(available).toLocaleString() + '.';
  if (investorCount !== null) output += ' Active investors: ' + investorCount + '.';
} else if (intent === 'CAMPAIGN') {
  // Real shape is POST /api/automation/campaign-batches: { generated, batchIds, totalItems }.
  // batchesCreated/totalBatches/batchCount never existed - batch count is batchIds.length.
  const items = firstNumber(data.itemsCreated, data.campaignItemsCreated, data.generated, data.count, data.totalItems);
  const batches = Array.isArray(data.batchIds) ? data.batchIds.length : firstNumber(data.batchesCreated, data.totalBatches, data.batchCount);
  output = 'Campaign Engine dispatch complete' + (items === null ? '' : ': ' + items + ' items') + (batches ? ' across ' + batches + ' batches' : '') + '.';
} else if (intent === 'OWNER_SKIP_TRACE') {
  const tasks = firstNumber(data.tasksCreated, data.generated, data.count, data.total, data.queueCount);
  output = 'Ownership Research dispatch complete' + (tasks === null ? '' : ': ' + tasks + ' tasks ready') + '.';
} else {
  const agent = data.agent || data.primaryAgent || 'ATLAS';
  const status = data.status || 'online';
  const engines = Array.isArray(data.engines) ? data.engines.length : firstNumber(data.engineCount, data.enginesOnline);
  output = agent + ' status: ' + status + '.' + (engines === null ? '' : ' Engines visible: ' + engines + '.');
  if (data.message) output += ' ' + data.message;
}

return [{ json: { output, intent, sessionId, raw: data } }];

const health = $json;
const body = $('Deal Intake: Webhook').item.json.body ?? $('Deal Intake: Webhook').item.json;
const apiOk = health?.ok === true && !health?.error;
return [{ json: { ...body, _apiOk: apiOk, _apiError: health?.error || null } }];

const body = items[0].json.body ?? items[0].json;
const required = ['purchase_price','repair_budget','arv','address'];
const missing  = required.filter(f => body[f] == null || body[f] === '');
if (missing.length) throw new Error(`Missing required fields: ${missing.join(', ')}`);
const pp  = Number(body.purchase_price);
const arv = Number(body.arv);
const rb  = Number(body.repair_budget) || 0;
if (pp  <= 0) throw new Error('purchase_price must be a positive number');
if (arv <= 0) throw new Error('arv must be a positive number');
if (arv <  pp) throw new Error('ARV cannot be less than purchase_price â€” check your numbers');
return [{ json: { ...body, purchase_price: pp, repair_budget: rb, arv,
  closing_costs:  Number(body.closing_costs)  || 0,
  holding_costs:  Number(body.holding_costs)  || 0,
  selling_costs:  Number(body.selling_costs)  || 0,
}}];

const validated = $('Deal Intake: Validate').item.json;
const lookupResult = $json;
const existing = lookupResult?.properties?.[0];
if (existing?.id) {
  return [{ json: { ...validated, property_id: existing.id, property_source: 'existing', need_create: false } }];
}
const code = (validated.address || 'PROP-' + Date.now())
  .replace(/[^a-zA-Z0-9]/g, '')
  .substring(0, 20)
  .toUpperCase() || ('PROP' + Date.now().toString().slice(-8));
const addrParts = (validated.address || '').split(',');
return [{ json: {
  ...validated,
  property_id: null,
  property_source: 'new',
  need_create: true,
  _create_body: {
    property_code: code,
    address: validated.address || '',
    city: addrParts[1]?.trim() || 'Unknown',
    state: addrParts[2]?.trim()?.split(' ')[0] || 'GA',
    acquisition_price: validated.purchase_price || null,
    estimated_arv: validated.arv || null,
    status: 'planning'
  }
} }];

const validated = $('Deal Intake: Validate').item.json;
// $json is either the new property record (has .id) or the prop-logic output (has .property_id)
const property_id = $json.id || $json.property_id || null;
const property_source = $json.id ? 'created' : ($json.property_source || 'existing');
return [{ json: { ...validated, property_id, property_source } }];

